   268→      handleCloseInfo={handleCloseInfo}
   269→      isLoading={isLoading}
   270→      hasError={hasError}
   271→      handleRetry={handleRetry}
   272→      isCashback={isCashback}
   273→      cardTitle={processedData.cardTitle}
   274→      formattedPointsValue={processedData.formattedPointsValue}
   275→      highlightText={processedData.highlightText}
   276→      formattedCurrencyValue={processedData.formattedCurrencyValue}
   277→      marketplaceContent={processedData.marketplaceContent}
   278→      showOrderNumber={processedData.showOrderNumber}
   279→      showStatus={processedData.showStatus}
   280→      showValue={processedData.showValue}
   281→      height={height}
   282→    />
   283→  );
   284→};
   285→
   286→export default MyOrdersDetails;
